def range_summary(nums):
    if not nums:  # empty list returns ''
        return ''

    distinct_nums = sorted(set(nums))
    result = []
    start_num = distinct_nums[0]
    end_num = None

    for num in distinct_nums:
        if num == end_num + 1:
            end_num = num
        else:
            if start_num == end_num:
                result.append(str(start_num))
            else:
                result.append(f'{start_num}-{end_num}')
            start_num = num
            end_num = None

    # handle last run
    if start_num == end_num:
        result.append(str(start_num))
    else:
        result.append(f'{start_num}-{end_num}')

    return ','.join(result)
